<template><main v-if='dish' class='detail'><button class='back' @click='$router.back()'>‹</button><img class='cover' :src='dish.image'/><section class='main card'><div class='title-row'><div><h1>{{dish.name}}</h1><p>{{dish.cuisine}} · {{dish.category}} · {{dish.taste}}</p></div><button class='fav' :class='{active:isFav}' @click='handleFavorite'>{{isFav?'♥':'♡'}}</button></div><p class='desc'>{{dish.description}}</p><div class='meta-grid'><div><strong>{{dish.cookingTime}}</strong><span>制作时间</span></div><div><strong>{{dish.difficulty}}</strong><span>难度</span></div><div><strong>{{selectedSpec.people}}人</strong><span>规格</span></div></div><h2>菜品规格</h2><div class='specs'><button v-for='item in dish.specs' :key='item.label' :class='{active:selectedSpec.label===item.label}' @click='selectedSpec=item'>{{item.label}}</button></div></section><section class='card block'><h2>所需食材</h2><div class='ingredients'><span v-for='item in dish.ingredients' :key='item'>{{item}}</span></div><h2>工具准备</h2><div class='ingredients'><span v-for='item in dish.tools' :key='item'>{{item}}</span></div></section><section class='card block'><h2>制作方法流程图</h2><article v-for='(step,index) in dish.steps' :key='index' class='step-card'><img :src='step.image'/><div><i>{{index+1}}</i><h3>{{step.title}} · {{step.duration}}</h3><p>{{step.text}}</p><b>提示：{{step.tip}}</b></div></article></section><div class='bottom safe-bottom'><button class='secondary-button' @click='$router.push(`/cook/${dish.id}`)'>开始做菜</button><button class='ios-button' @click='handleAdd'>加入今日菜单</button></div></main></template><script setup>import{computed,onMounted,ref,watchEffect}from'vue';import{useRoute}from'vue-router';import{useRecipes}from'../composables/useRecipes';import{addCart,getFavorites,toggleFavorite}from'../utils/storage';const route=useRoute();const{dishes,loadRecipes}=useRecipes();const selectedSpec=ref({}),isFav=ref(false);onMounted(loadRecipes);const dish=computed(()=>dishes.value.find(x=>x.id===Number(route.params.id)));watchEffect(()=>{if(dish.value&&!selectedSpec.value.label)selectedSpec.value=dish.value.specs?.[0]||{};if(dish.value)isFav.value=getFavorites().includes(dish.value.id)});function handleAdd(){addCart({...dish.value,selectedSpec:selectedSpec.value,cartId:Date.now()});alert('已加入今日菜单')}function handleFavorite(){isFav.value=toggleFavorite(dish.value.id)}</script><style scoped>.detail{min-height:100vh;padding-bottom:116px;background:var(--bg)}.back{position:fixed;top:18px;left:calc(50% - min(50vw,215px) + 14px);width:42px;height:42px;border:0;border-radius:50%;background:rgba(255,255,255,.82);font-size:34px;z-index:5}.cover{width:100%;height:360px;object-fit:cover}.main{position:relative;z-index:2;margin:-42px 16px 16px;padding:22px}.title-row{display:flex;justify-content:space-between;gap:14px}h1{margin:0;font-size:29px}.title-row p{margin:7px 0 0;color:var(--sub);font-size:14px}.fav{width:46px;height:46px;border:0;border-radius:50%;background:#f2f2f7;color:var(--red);font-size:28px}.desc{margin:18px 0;color:#3a3a3c;font-size:15px;line-height:1.65}.meta-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.meta-grid div{padding:14px 8px;border-radius:18px;background:#f5f5f7;text-align:center}.meta-grid strong{display:block;font-size:15px}.meta-grid span{display:block;margin-top:5px;color:var(--sub);font-size:12px}h2{margin:22px 0 12px;font-size:19px}.specs,.ingredients{display:flex;gap:9px;flex-wrap:wrap}.specs button,.ingredients span{border:0;padding:9px 13px;border-radius:999px;background:#f2f2f7;font-weight:900;color:var(--text);font-size:13px}.specs button.active{background:var(--blue);color:#fff}.block{margin:16px;padding:22px}.step-card{display:flex;gap:13px;padding:12px 0;border-bottom:1px solid var(--line)}.step-card:last-child{border-bottom:0}.step-card img{width:104px;height:84px;border-radius:18px;object-fit:cover;background:#eee;flex-shrink:0}.step-card div{min-width:0}.step-card i{display:inline-flex;align-items:center;justify-content:center;width:26px;height:26px;border-radius:50%;background:var(--blue);color:#fff;font-style:normal;font-size:12px;font-weight:900}.step-card h3{display:inline-block;margin:0 0 0 8px;font-size:15px}.step-card p{margin:8px 0 0;color:#3a3a3c;line-height:1.55;font-size:14px}.step-card b{display:block;margin-top:6px;color:var(--orange);font-size:12px}.bottom{position:fixed;left:50%;bottom:0;transform:translateX(-50%);width:min(100%,430px);display:grid;grid-template-columns:1fr 1fr;gap:10px;padding:14px 16px 28px;background:rgba(255,255,255,.82);backdrop-filter:blur(22px);border-top:1px solid rgba(0,0,0,.06);z-index:10}</style>
